1	import { useCallback, useEffect, useRef, useState } from "react";
2	import { ChevronDown, Trash2, X } from "lucide-react";
3	import { getProviders } from "@earendil-works/pi-ai";
4	import { getAppStorage } from "@earendil-works/pi-web-ui";
5	import {
6		loadKeatingUiSettings,
7		toggleProviderVisibility,
8		addCustomModel,
9		removeCustomModel,
10	} from "../keating/ui-settings";
11	import { handleTutorialLinkClick, tutorialApiKeyHref } from "../lib/tutorial-links";
12	import { SettingsSectionNav } from "./SettingsSectionNav";
13	import { Toggle } from "./Toggle";
14	import {
15		discoverCustomProviderModels,
16		type KeatingCustomProvider,
17		type KeatingCustomProviderType,
18		type KeatingGatewayKind,
19	} from "../lib/provider-models";
20	import {
21		completeOAuthFromInput,
22		initiateOAuth,
23		providerToOAuthId,
24		loadOAuthCredentials,
25		deleteOAuthCredentials,
26		type OAuthProviderId,
27	} from "../keating/oauth";
28	
29	const AUTO_DISCOVERY_TYPES = new Set<KeatingCustomProviderType>([
30		"ollama", "llama.cpp", "vllm", "lmstudio", "gateway",
31		"openai-completions", "openai-responses", "synthetic",
32	]);
33	
34	const PROVIDER_PRIORITY = ["openai", "anthropic", "google"];
35	
36	function sortProvidersByPriority(list: string[]): string[] {
37		const rank = (name: string) => {
38			const idx = PROVIDER_PRIORITY.indexOf(name);
39			return idx === -1 ? PROVIDER_PRIORITY.length : idx;
40		};
41		return [...list].sort((a, b) => {
42			const ra = rank(a);
43			const rb = rank(b);
44			if (ra !== rb) return ra - rb;
45			return a.localeCompare(b);
46		});
47	}
48	
49	const PROVIDER_TYPE_OPTIONS = [
50		{ value: "ollama", label: "Ollama" },
51		{ value: "llama.cpp", label: "llama.cpp" },
52		{ value: "vllm", label: "vLLM" },
53		{ value: "lmstudio", label: "LM Studio" },
54		{ value: "gateway", label: "AI Gateway" },
55		{ value: "openai-completions", label: "OpenAI Completions Compatible" },
56		{ value: "openai-responses", label: "OpenAI Responses Compatible" },
57		{ value: "anthropic-messages", label: "Anthropic Messages Compatible" },
58		{ value: "synthetic", label: "Synthetic (OpenAI Compatible)" },
59	];
60	
61	const GATEWAY_KIND_OPTIONS: Array<{ value: KeatingGatewayKind; label: string }> = [
62		{ value: "bifrost", label: "Bifrost" },
63		{ value: "plexus", label: "Plexus" },
64		{ value: "litellm", label: "LiteLLM" },
65		{ value: "generic", label: "Other OpenAI-compatible gateway" },
66	];
67	
68	const GATEWAY_DEFAULT_URLS: Record<KeatingGatewayKind, string> = {
69		bifrost: "http://localhost:8080",
70		plexus: "",
71		litellm: "http://localhost:4000",
72		generic: "",
73	};
74	
75	const ADD_MODEL_APIS = [
76		{ value: "openai-completions", label: "OpenAI Completions" },
77		{ value: "openai-responses", label: "OpenAI Responses" },
78		{ value: "anthropic-messages", label: "Anthropic Messages" },
79		{ value: "google", label: "Google" },
80	];
81	
82	export function ProvidersModelsTab() {
83		const [customProviders, setCustomProviders] = useState<KeatingCustomProvider[]>([]);
84		const [settings, setSettings] = useState(() => loadKeatingUiSettings());
85		const [showAddModel, setShowAddModel] = useState(false);
86		const [addProviderMenuOpen, setAddProviderMenuOpen] = useState(false);
87		const addProviderMenuRef = useRef<HTMLDivElement>(null);
88		const [providerDialog, setProviderDialog] = useState<{ open: boolean; provider?: KeatingCustomProvider; type?: KeatingCustomProviderType }>({ open: false });
89		const [modelError, setModelError] = useState("");
90		const [providerError, setProviderError] = useState("");
91		const [modelForm, setModelForm] = useState({
92			name: "",
93			id: "",
94			provider: "openai",
95			api: "openai-completions",
96			baseUrl: "",
97			reasoning: false,
98			vision: false,
99		});
100	
101		const [providerForm, setProviderForm] = useState({
102			name: "",
103			type: "openai-completions" as KeatingCustomProviderType,
104			gatewayKind: "bifrost" as KeatingGatewayKind,
105			baseUrl: "",
106			apiKey: "",
107		});
108	
109		useEffect(() => {
110			loadCustomProviders().then(setCustomProviders);
111		}, [providerDialog.open]);
112	
113		useEffect(() => {
114			setProviderError("");
115			if (!providerDialog.open) {
116				setProviderForm({ name: "", type: "openai-completions", gatewayKind: "bifrost", baseUrl: "", apiKey: "" });
117				return;
118			}
119			if (providerDialog.provider) {
120				// Also fetch apiKey from providerKeys storage in case it was stored separately
121				const storage = getAppStorage();
122				let apiKey = providerDialog.provider.apiKey ?? "";
123				storage.providerKeys.get(providerDialog.provider.name).then((key) => {
124					if (key) {
125						setProviderForm((prev) => ({ ...prev, apiKey: key }));
126					}
127				}).catch(() => {});
128				setProviderForm({
129					name: providerDialog.provider.name,
130					type: providerDialog.provider.type,
131					gatewayKind: providerDialog.provider.gatewayKind ?? "bifrost",
132					baseUrl: providerDialog.provider.baseUrl,
133					apiKey,
134				});
135			} else if (providerDialog.type) {
136				const defaults: Record<KeatingCustomProviderType, string> = {
137					ollama: "http://localhost:11434",
138					"llama.cpp": "http://localhost:8080",
139					vllm: "http://localhost:8000",
140					lmstudio: "http://localhost:1234",
141					gateway: GATEWAY_DEFAULT_URLS.bifrost,
142					"openai-completions": "",
143					"openai-responses": "",
144					"anthropic-messages": "",
145					synthetic: "https://api.synthetic.new/openai/v1",
146				};
147				setProviderForm({
148					name: "",
149					type: providerDialog.type,
150					gatewayKind: "bifrost",
151					baseUrl: defaults[providerDialog.type] || "",
152					apiKey: "",
153				});
154			}
155		}, [providerDialog.provider, providerDialog.type]);
156	
157		const refresh = useCallback(() => {
158			setSettings(loadKeatingUiSettings());
159		}, []);
160	
161		const providers = sortProvidersByPriority(getProviders());
162	
163		const handleToggleProvider = (provider: string, hidden: boolean) => {
164			toggleProviderVisibility(provider, hidden);
165			refresh();
166		};
167	
168		const handleSaveModel = () => {
169			setModelError("");
170			const name = modelForm.name.trim();
171			const id = modelForm.id.trim();
172			const provider = modelForm.provider.trim();
173			if (!name || !id || !provider) {
174				setModelError("Name, ID, and Provider are required");
175				return;
176			}
177			const key = `${provider}::${modelForm.api}::${id}`;
178			addCustomModel({
179				key,
180				id,
181				name,
182				provider,
183				api: modelForm.api,
184				baseUrl: modelForm.baseUrl.trim() || undefined,
185				reasoning: modelForm.reasoning,
186				vision: modelForm.vision,
187			});
188			setSettings(loadKeatingUiSettings());
189			setShowAddModel(false);
190			setModelForm({ name: "", id: "", provider: "openai", api: "openai-completions", baseUrl: "", reasoning: false, vision: false });
191		};
192	
193		const handleSaveProvider = async () => {
194			setProviderError("");
195			if (!providerForm.name.trim() || !providerForm.baseUrl.trim()) {
196				setProviderError("Name and Base URL are required");
197				return;
198			}
199			const isEdit = !!providerDialog.provider;
200			try {
201				const storage = getAppStorage();
202				const providerId = providerDialog.provider?.id ?? crypto.randomUUID();
203				let provider: KeatingCustomProvider = {
204					id: providerId,
205					name: providerForm.name.trim(),
206					type: providerForm.type,
207					gatewayKind: providerForm.type === "gateway" ? providerForm.gatewayKind : undefined,
208					baseUrl: providerForm.baseUrl.trim(),
209					apiKey: providerForm.apiKey.trim() || undefined,
210					models: providerDialog.provider?.models ?? [],
211				};
212				if (AUTO_DISCOVERY_TYPES.has(provider.type)) {
213					const models = await discoverCustomProviderModels(provider);
214					if (models.length === 0) {
215						setProviderError("Connected successfully, but the provider returned no models. Check the base URL and key.");
216						return;
217					}
218					provider = { ...provider, models };
219				}
220				await storage.customProviders.set(provider as any);
221				if (providerForm.apiKey.trim()) {
222					await storage.providerKeys.set(provider.name, providerForm.apiKey.trim());
223				}
224				await loadCustomProviders().then(setCustomProviders);
225				setProviderDialog({ open: false });
226				setProviderForm({ name: "", type: "openai-completions", gatewayKind: "bifrost", baseUrl: "", apiKey: "" });
227			} catch (error) {
228				console.error("Failed to save provider:", error);
229				const message = error instanceof Error ? error.message : "Unknown connection error";
230				setProviderError(`${isEdit ? "Failed to update" : "Failed to save"} provider: ${message}`);
231			}
232		};
233	
234		const handleDeleteProvider = async (provider: KeatingCustomProvider) => {
235			if (!confirm("Are you sure you want to delete this provider?")) return;
236			try {
237				const storage = getAppStorage();
238				await storage.customProviders.delete(provider.id);
239				await storage.providerKeys.delete(provider.name);
240				await loadCustomProviders().then(setCustomProviders);
241			} catch (error) {
242				console.error("Failed to delete provider:", error);
243			}
244		};
245	
246		const openAddProvider = (type: KeatingCustomProviderType) => {
247			setProviderDialog({ open: true, type });
248			setAddProviderMenuOpen(false);
249		};
250	
251		useEffect(() => {
252			if (!addProviderMenuOpen) return;
253			const onDown = (event: MouseEvent) => {
254				if (!addProviderMenuRef.current?.contains(event.target as Node)) {
255					setAddProviderMenuOpen(false);
256				}
257			};
258			window.addEventListener("mousedown", onDown);
259			return () => window.removeEventListener("mousedown", onDown);
260		}, [addProviderMenuOpen]);
261	
262		return (
263			<div className="flex flex-col gap-8">
264				<SettingsSectionNav
265					sections={[
266						{ id: "cloud-providers", label: "Cloud" },
267						{ id: "provider-visibility", label: "Visibility" },
268						{ id: "my-models", label: "My Models" },
269						{ id: "custom-providers", label: "Custom Providers" },
270					]}
271				/>
272	
273				{/* Cloud Provider Keys */}
274				<div id="settings-section-cloud-providers" className="flex flex-col gap-4 scroll-mt-20">
275					<div>
276						<h3 className="text-sm font-semibold text-foreground mb-2">Cloud Providers</h3>
277						<p className="text-sm text-muted-foreground">
278							Cloud LLM providers with predefined models. API keys are stored locally in your browser.
279						</p>
280					</div>
281					<div className="flex flex-col gap-3">
282						<OAuthProviderKeys
283							providers={providers.filter((p) => !settings.hiddenProviders.includes(p))}
284						/>
285					</div>
286				</div>
287	
288				<div className="border-t border-border" />
289	
290				{/* Provider Visibility */}
291				<div id="settings-section-provider-visibility" className="flex flex-col gap-4 scroll-mt-20">
292					<div>
293						<h3 className="text-sm font-semibold text-foreground mb-2">Provider Visibility</h3>
294						<p className="text-sm text-muted-foreground">
295							Hide providers you don't use to declutter the model selector.
296						</p>
297					</div>
298					<div className="flex flex-col gap-3">
299						{providers.map((provider) => {
300							const hidden = settings.hiddenProviders.includes(provider);
301							return (
302								<div key={provider} className="flex items-center justify-between gap-4 rounded-lg border border-border p-3">
303									<div className="text-sm font-medium text-foreground capitalize">{provider}</div>
304									<Toggle
305										tone="success"
306										aria-label={hidden ? "Hidden" : "Visible"}
307										checked={!hidden}
308										onChange={(checked) => handleToggleProvider(provider, !checked)}
309									/>
310								</div>
311							);
312						})}
313					</div>
314				</div>
315	
316				<div className="border-t border-border" />
317	
318				{/* Custom Models */}
319				<div id="settings-section-my-models" className="flex flex-col gap-4 scroll-mt-20">
320					<div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between sm:gap-4">
321						<div className="min-w-0">
322							<h3 className="text-sm font-semibold text-foreground mb-2">My Models</h3>
323							<p className="text-sm text-muted-foreground">
324								Manually add models that aren't auto-discovered.
325							</p>
326						</div>
327						<button
328							className="dialog-compact-button inline-flex shrink-0 items-center justify-center rounded-md border border-border px-3 py-1.5 text-xs font-medium hover:bg-accent hover:text-accent-foreground transition-colors"
329							onClick={() => setShowAddModel((s) => !s)}
330						>
331							{showAddModel ? "Cancel" : "Add Model"}
332						</button>
333					</div>
334	
335					{showAddModel && (
336						<div className="flex flex-col gap-3 rounded-lg border border-border p-4 bg-muted/30">
337							{modelError && (
338								<div className="rounded-md border border-destructive/30 bg-destructive/5 px-3 py-2 text-sm text-destructive">
339									{modelError}
340								</div>
341							)}
342							<div className="flex flex-col gap-2">
343								<label className="text-sm font-medium text-foreground">Model Name</label>
344								<input
345									type="text"
346									className="rounded-md border border-border bg-background px-3 py-2 text-sm"
347									placeholder="e.g., GPT-5"
348									value={modelForm.name}
349									onChange={(e) => setModelForm((f) => ({ ...f, name: e.target.value }))}
350								/>
351							</div>
352							<div className="flex flex-col gap-2">
353								<label className="text-sm font-medium text-foreground">Model ID</label>
354								<input
355									type="text"
356									className="rounded-md border border-border bg-background px-3 py-2 text-sm"
357									placeholder="e.g., gpt-5"
358									value={modelForm.id}
359									onChange={(e) => setModelForm((f) => ({ ...f, id: e.target.value }))}
360								/>
361							</div>
362							<div className="flex flex-col gap-2">
363								<label className="text-sm font-medium text-foreground">Provider</label>
364								<select
365									className="rounded-md border border-border bg-background px-3 py-2 text-sm"
366									value={modelForm.provider}
367									onChange={(e) => setModelForm((f) => ({ ...f, provider: e.target.value }))}
368								>
369									{getProviders().map((p) => (
370										<option key={p} value={p}>{p}</option>
371									))}
372									<option value="custom">Custom</option>
373								</select>
374							</div>
375							<div className="flex flex-col gap-2">
376								<label className="text-sm font-medium text-foreground">API Type</label>
377								<select
378									className="rounded-md border border-border bg-background px-3 py-2 text-sm"
379									value={modelForm.api}
380									onChange={(e) => setModelForm((f) => ({ ...f, api: e.target.value }))}
381								>
382									{ADD_MODEL_APIS.map((a) => (
383										<option key={a.value} value={a.value}>{a.label}</option>
384									))}
385								</select>
386							</div>
387							<div className="flex flex-col gap-2">
388								<label className="text-sm font-medium text-foreground">Base URL (Optional)</label>
389								<input
390									type="text"
391									className="rounded-md border border-border bg-background px-3 py-2 text-sm"
392									placeholder="e.g., https://api.openai.com/v1"
393									value={modelForm.baseUrl}
394									onChange={(e) => setModelForm((f) => ({ ...f, baseUrl: e.target.value }))}
395								/>
396							</div>
397							<div className="flex gap-4">
398								<label className="flex items-center gap-2 text-sm">
399									<input
400										type="checkbox"
401										checked={modelForm.reasoning}
402										onChange={(e) => setModelForm((f) => ({ ...f, reasoning: e.target.checked }))}
403									/>
404									Reasoning
405								</label>
406								<label className="flex items-center gap-2 text-sm">
407									<input
408										type="checkbox"
409										checked={modelForm.vision}
410										onChange={(e) => setModelForm((f) => ({ ...f, vision: e.target.checked }))}
411									/>
412									Vision
413								</label>
414							</div>
415							<div className="flex justify-end">
416								<button
417									className="inline-flex items-center justify-center rounded-md bg-primary px-3 py-1.5 text-xs font-medium text-primary-foreground hover:bg-primary/90 transition-colors disabled:opacity-50"
418									disabled={!modelForm.name.trim() || !modelForm.id.trim() || !modelForm.provider.trim()}
419									onClick={handleSaveModel}
420								>
421									Save Model
422								</button>
423							</div>
424						</div>
425					)}
426	
427					{settings.customModels.length === 0 ? (
428						<div className="text-sm text-muted-foreground text-center py-6">No custom models added yet.</div>
429					) : (
430						<div className="flex flex-col gap-3">
431							{settings.customModels.map((model) => (
432								<div key={model.key} className="flex items-center justify-between gap-4 rounded-lg border border-border p-3">
433									<div className="min-w-0">
434										<div className="text-sm font-medium text-foreground">{model.name}</div>
435										<div className="text-xs text-muted-foreground">{model.provider} / {model.id} / {model.api}</div>
436									</div>
437									<button
438										className="inline-flex items-center justify-center rounded-md px-2 py-1 text-xs text-muted-foreground hover:bg-accent hover:text-accent-foreground transition-colors"
439										onClick={() => {
440											removeCustomModel(model.key);
441											setSettings(loadKeatingUiSettings());
442										}}
443									>
444										Delete
445									</button>
446								</div>
447							))}
448						</div>
449					)}
450				</div>
451	
452				<div className="border-t border-border" />
453	
454				{/* Custom Providers */}
455				<div id="settings-section-custom-providers" className="flex flex-col gap-4 scroll-mt-20">
456					<div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between sm:gap-4">
457						<div className="min-w-0">
458							<h3 className="text-sm font-semibold text-foreground mb-2">Custom Providers</h3>
459							<p className="text-sm text-muted-foreground">
460								User-configured servers with auto-discovered or manually defined models.
461							</p>
462						</div>
463						<div ref={addProviderMenuRef} className="relative w-full sm:w-auto shrink-0">
464							<button
465								type="button"
466								aria-haspopup="menu"
467								aria-expanded={addProviderMenuOpen}
468								onClick={() => setAddProviderMenuOpen((open) => !open)}
469								className="inline-flex w-full sm:w-auto items-center justify-between gap-2 rounded-md border border-border bg-background px-3 py-1.5 text-xs font-medium hover:bg-accent hover:text-accent-foreground transition-colors"
470							>
471								<span>Add Provider</span>
472								<ChevronDown
473									size={12}
474									className={`transition-transform ${addProviderMenuOpen ? "rotate-180" : ""}`}
475								/>
476							</button>
477							{addProviderMenuOpen ? (
478								<div
479									role="menu"
480									className="absolute right-0 top-9 z-30 w-64 overflow-hidden rounded-lg border border-border bg-background py-1 shadow-lg"
481								>
482									{PROVIDER_TYPE_OPTIONS.map((option) => (
483										<button
484											key={option.value}
485											type="button"
486											role="menuitem"
487											className="flex w-full items-center px-3 py-2 text-left text-xs hover:bg-accent hover:text-accent-foreground transition-colors"
488											onClick={() => openAddProvider(option.value as KeatingCustomProviderType)}
489										>
490											{option.label}
491										</button>
492									))}
493								</div>
494							) : null}
495						</div>
496					</div>
497	
498					{customProviders.length === 0 ? (
499						<div className="text-sm text-muted-foreground text-center py-8">
500							No custom providers configured. Click &quot;Add Provider&quot; to get started.
501						</div>
502					) : (
503						<div className="flex flex-col gap-4">
504							{customProviders.map((provider) => (
505								<CustomProviderCard
506									key={provider.id}
507									provider={provider}
508									isAutoDiscovery={AUTO_DISCOVERY_TYPES.has(provider.type as KeatingCustomProviderType)}
509									onEdit={() => setProviderDialog({ open: true, provider })}
510									onDelete={() => handleDeleteProvider(provider)}
511								/>
512							))}
513						</div>
514					)}
515				</div>
516	
517				{/* Provider Dialog */}
518				{providerDialog.open && (
519					<div
520						className="fixed inset-0 z-[1001] flex items-center justify-center bg-black/50 backdrop-blur-sm px-4"
521						role="dialog"
522						aria-modal="true"
523						aria-label={providerDialog.provider ? "Edit Provider" : "Add Provider"}
524						onClick={() => setProviderDialog({ open: false })}
525					>
526						<div className="w-full max-w-md rounded-lg border border-border bg-background p-5 shadow-lg" onClick={(e) => e.stopPropagation()}>
527							<div className="flex items-center justify-between mb-4">
528								<h3 className="text-sm font-semibold text-foreground">
529									{providerDialog.provider ? "Edit Provider" : "Add Provider"}
530								</h3>
531								<button onClick={() => setProviderDialog({ open: false })} className="h-7 w-7 inline-flex items-center justify-center rounded-md text-muted-foreground hover:bg-accent">
532									<X size={14} />
533								</button>
534							</div>
535							<div className="flex flex-col gap-3">
536								<div className="flex flex-col gap-1">
537									<label className="text-sm font-medium text-foreground">Provider Name</label>
538									<input
539										type="text"
540										className="rounded-md border border-border bg-background px-3 py-2 text-sm"
541										placeholder="e.g., My Ollama Server"
542										value={providerForm.name}
543										onChange={(e) => setProviderForm((f) => ({ ...f, name: e.target.value }))}
544									/>
545								</div>
546								<div className="flex flex-col gap-1">
547									<label className="text-sm font-medium text-foreground">Provider Type</label>
548									<select
549										className="rounded-md border border-border bg-background px-3 py-2 text-sm"
550										value={providerForm.type}
551										onChange={(e) => {
552											const t = e.target.value as KeatingCustomProviderType;
553											setProviderForm((f) => ({ ...f, type: t }));
554										}}
555									>
556										{PROVIDER_TYPE_OPTIONS.map((o) => (
557											<option key={o.value} value={o.value}>{o.label}</option>
558										))}
559									</select>
560								</div>
561								{providerForm.type === "gateway" && (
562									<div className="flex flex-col gap-1">
563										<label className="text-sm font-medium text-foreground">Gateway Kind</label>
564										<select
565											className="rounded-md border border-border bg-background px-3 py-2 text-sm"
566											value={providerForm.gatewayKind}
567											onChange={(e) => {
568												const gatewayKind = e.target.value as KeatingGatewayKind;
569												setProviderForm((form) => ({
570													...form,
571													gatewayKind,
572													baseUrl: GATEWAY_DEFAULT_URLS[gatewayKind],
573												}));
574											}}
575										>
576											{GATEWAY_KIND_OPTIONS.map((option) => (
577												<option key={option.value} value={option.value}>{option.label}</option>
578											))}
579										</select>
580									</div>
581								)}
582								<div className="flex flex-col gap-1">
583									<label className="text-sm font-medium text-foreground">Base URL</label>
584									<input
585										type="text"
586										className="rounded-md border border-border bg-background px-3 py-2 text-sm"
587										placeholder="e.g., https://api.ollama.local"
588										value={providerForm.baseUrl}
589										onChange={(e) => setProviderForm((f) => ({ ...f, baseUrl: e.target.value }))}
590									/>
591								</div>
592								<div className="flex flex-col gap-1">
593									<label className="text-sm font-medium text-foreground">API Key (Optional)</label>
594									<input
595										type="password"
596										className="rounded-md border border-border bg-background px-3 py-2 text-sm"
597										placeholder="Leave empty if not required"
598										value={providerForm.apiKey}
599										onChange={(e) => setProviderForm((f) => ({ ...f, apiKey: e.target.value }))}
600									/>
601								</div>
602								{providerError && (
603									<div className="rounded-md border border-destructive/30 bg-destructive/5 px-3 py-2 text-sm text-destructive">
604										{providerError}
605									</div>
606								)}
607								<div className="flex justify-end gap-2 mt-2">
608									<button
609										className="rounded-md border border-border px-3 py-1.5 text-xs text-muted-foreground hover:bg-accent transition-colors"
610										onClick={() => setProviderDialog({ open: false })}
611									>
612										Cancel
613									</button>
614									<button
615										className="rounded-md bg-primary px-3 py-1.5 text-xs font-medium text-primary-foreground hover:bg-primary/90 transition-colors disabled:opacity-50"
616										disabled={!providerForm.name.trim() || !providerForm.baseUrl.trim()}
617										onClick={handleSaveProvider}
618									>
619										Save
620									</button>
621								</div>
622							</div>
623						</div>
624					</div>
625				)}
626			</div>
627		);
628	}
629	
630	async function loadCustomProviders(): Promise<KeatingCustomProvider[]> {
631		try {
632			const storage = getAppStorage();
633			return (await storage.customProviders.getAll()) as KeatingCustomProvider[];
634		} catch (error) {
635			console.error("Failed to load custom providers:", error);
636			return [];
637		}
638	}
639	
640	function OAuthProviderKeys({ providers }: { providers: string[] }) {
641		const [keys, setKeys] = useState<Record<string, string>>({});
642		const [oauthStatus, setOAuthStatus] = useState<Record<string, boolean>>({});
643		const [oauthLoading, setOauthLoading] = useState<Record<string, boolean>>({});
644		const [oauthInputs, setOAuthInputs] = useState<Record<string, string>>({});
645		const [oauthErrors, setOAuthErrors] = useState<Record<string, string>>({});
646	
647		useEffect(() => {
648			const storage = getAppStorage();
649			Promise.all(providers.map(async (p) => ({
650				provider: p,
651				key: (await storage.providerKeys.get(p)) ?? "",
652			}))).then((results) => {
653				const map: Record<string, string> = {};
654				for (const { provider, key } of results) map[provider] = key;
655				setKeys(map);
656			});
657		}, [providers.join(",")]);
658	
659		useEffect(() => {
660			const checkOAuth = async () => {
661				const status: Record<string, boolean> = {};
662				for (const provider of providers) {
663					const oauthId = providerToOAuthId(provider);
664					if (oauthId) {
665						const creds = await loadOAuthCredentials(oauthId);
666						status[provider] = !!creds;
667					}
668				}
669				setOAuthStatus(status);
670			};
671			checkOAuth();
672		}, [providers.join(",")]);
673	
674		useEffect(() => {
675			const handler = (event: MessageEvent) => {
676				if (event.data?.type !== "keating-oauth-result") return;
677				const { success, provider: oauthProvider } = event.data;
678				const providerNames = oauthProviderToProviderNames(oauthProvider);
679				if (success && oauthProvider) {
680					setOAuthStatus((prev) => setProviderAliases(prev, providerNames, true));
681					setOAuthInputs((prev) => setProviderAliases(prev, providerNames, ""));
682					setOAuthErrors((prev) => setProviderAliases(prev, providerNames, ""));
683				} else if (providerNames.length > 0) {
684					setOAuthErrors((prev) => setProviderAliases(prev, providerNames, event.data.error ?? "OAuth sign-in failed."));
685				}
686				setOauthLoading((prev) => {
687					const next = { ...prev };
688					for (const k of Object.keys(next)) next[k] = false;
689					return next;
690				});
691			};
692			window.addEventListener("message", handler);
693			return () => window.removeEventListener("message", handler);
694		}, []);
695	
696		const save = async (provider: string, value: string) => {
697			const storage = getAppStorage();
698			if (value.trim()) {
699				await storage.providerKeys.set(provider, value.trim());
700			} else {
701				await storage.providerKeys.delete(provider);
702			}
703		};
704	
705		const handleSignIn = (provider: string) => {
706			const oauthId = providerToOAuthId(provider);
707			if (!oauthId) return;
708			setOAuthErrors((prev) => ({ ...prev, [provider]: "" }));
709			setOAuthInputs((prev) => ({ ...prev, [provider]: "" }));
710			setOauthLoading((prev) => ({ ...prev, [provider]: true }));
711			initiateOAuth(oauthId);
712		};
713	
714		const handleCompleteOAuth = async (provider: string) => {
715			const input = oauthInputs[provider]?.trim() ?? "";
716			if (!input) {
717				setOAuthErrors((prev) => ({ ...prev, [provider]: "Paste the callback URL or authorization code first." }));
718				return;
719			}
720			setOauthLoading((prev) => ({ ...prev, [provider]: true }));
721			setOAuthErrors((prev) => ({ ...prev, [provider]: "" }));
722			const result = await completeOAuthFromInput(input);
723			if (result.success && result.provider) {
724				const statusProviders = oauthProviderToProviderNames(result.provider);
725				setOAuthStatus((prev) => setProviderAliases(prev, statusProviders, true));
726				setOAuthInputs((prev) => ({ ...prev, [provider]: "" }));
727			} else {
728				setOAuthErrors((prev) => ({ ...prev, [provider]: result.error ?? "OAuth sign-in failed." }));
729			}
730			setOauthLoading((prev) => ({ ...prev, [provider]: false }));
731		};
732	
733		const handleSignOut = async (provider: string) => {
734			const oauthId = providerToOAuthId(provider);
735			if (!oauthId) return;
736			await deleteOAuthCredentials(oauthId);
737			const storage = getAppStorage();
738			await storage.providerKeys.delete(provider);
739			setOAuthStatus((prev) => ({ ...prev, [provider]: false }));
740			setKeys((prev) => ({ ...prev, [provider]: "" }));
741		};
742	
743		const OAUTH_PROVIDER_LABELS: Record<string, string> = {
744			anthropic: "Anthropic",
745			"openai-codex": "OpenAI Codex",
746			google: "Google Gemini",
747		};
748	
749		return (
750			<>
751				{providers.map((provider) => {
752					const oauthId = providerToOAuthId(provider);
753					const isOAuth = !!oauthId;
754					const hasOAuth = oauthStatus[provider] === true;
755					const loading = oauthLoading[provider] === true;
756	
757					if (isOAuth) {
758						return (
759							<div key={provider} className="flex flex-col gap-1">
760								<div className="flex items-center justify-between gap-3">
761									<label className="text-xs font-medium text-muted-foreground capitalize">
762										{OAUTH_PROVIDER_LABELS[provider] ?? provider}
763									</label>
764									<a
765										href={tutorialApiKeyHref(provider)}
766										onClick={(event) => handleTutorialLinkClick(event.nativeEvent, tutorialApiKeyHref(provider))}
767										className="text-xs text-primary underline underline-offset-2"
768									>
769										Get a key
770									</a>
771								</div>
772								{hasOAuth ? (
773									<div className="flex items-center justify-between gap-3 rounded-md border border-border bg-muted/30 px-3 py-2">
774										<span className="text-sm text-muted-foreground">Signed in</span>
775										<button
776											className="text-xs text-muted-foreground hover:text-foreground underline underline-offset-2"
777											onClick={() => handleSignOut(provider)}
778										>
779											Sign out
780										</button>
781									</div>
782								) : (
783									<div className="flex flex-col gap-2">
784										<button
785											className="inline-flex items-center justify-center rounded-md bg-primary px-3 py-2 text-sm font-medium text-primary-foreground hover:bg-primary/90 transition-colors disabled:opacity-50"
786											disabled={loading}
787											onClick={() => handleSignIn(provider)}
788										>
789											{loading ? "Waiting for sign-in…" : `Sign in with ${OAUTH_PROVIDER_LABELS[provider] ?? provider}`}
790										</button>
791										{loading && (
792											<div className="rounded-md border border-border bg-muted/20 p-2">
793												<p className="mb-2 text-xs text-muted-foreground">
794													If the provider redirects to a localhost callback that does not load, paste that final URL here.
795												</p>
796												<div className="flex gap-2">
797													<input
798														type="text"
799														className="min-w-0 flex-1 rounded-md border border-border bg-background px-2 py-1.5 text-xs"
800														placeholder="Callback URL or authorization code"
801														value={oauthInputs[provider] ?? ""}
802														onChange={(e) => setOAuthInputs((prev) => ({ ...prev, [provider]: e.target.value }))}
803													/>
804													<button
805														className="rounded-md border border-border px-2 py-1.5 text-xs font-medium hover:bg-accent hover:text-accent-foreground transition-colors disabled:opacity-50"
806														disabled={!oauthInputs[provider]?.trim()}
807														onClick={() => handleCompleteOAuth(provider)}
808													>
809														Complete
810													</button>
811												</div>
812											</div>
813										)}
814										{oauthErrors[provider] && (
815											<div className="rounded-md border border-destructive/30 bg-destructive/5 px-3 py-2 text-xs text-destructive">
816												{oauthErrors[provider]}
817											</div>
818										)}
819									</div>
820								)}
821							</div>
822						);
823					}
824	
825					return (
826						<div key={provider} className="flex flex-col gap-1">
827							<div className="flex items-center justify-between gap-3">
828								<label className="text-xs font-medium text-muted-foreground capitalize">{provider} API Key</label>
829								<a
830									href={tutorialApiKeyHref(provider)}
831									onClick={(event) => handleTutorialLinkClick(event.nativeEvent, tutorialApiKeyHref(provider))}
832									className="text-xs text-primary underline underline-offset-2"
833								>
834									Get a key
835								</a>
836							</div>
837							<input
838								type="password"
839								className="rounded-md border border-border bg-background px-3 py-2 text-sm"
840								placeholder={`${provider} API key`}
841								value={keys[provider] ?? ""}
842								onChange={(e) => setKeys((prev) => ({ ...prev, [provider]: e.target.value }))}
843								onBlur={(e) => save(provider, e.target.value)}
844							/>
845						</div>
846					);
847				})}
848			</>
849		);
850	}
851	
852	function oauthProviderToProviderNames(provider: OAuthProviderId | string | undefined): string[] {
853		if (provider === "google-gemini-cli") return ["google"];
854		if (provider === "openai-codex") return ["openai-codex"];
855		if (provider === "anthropic") return ["anthropic"];
856		return provider ? [provider] : [];
857	}
858	
859	function setProviderAliases<T>(prev: Record<string, T>, providers: string[] | string, value: T): Record<string, T> {
860		const next = { ...prev };
861		for (const provider of Array.isArray(providers) ? providers : [providers]) {
862			next[provider] = value;
863		}
864		return next;
865	}
866	
867	function CustomProviderCard({
868		provider,
869		isAutoDiscovery,
870		onEdit,
871		onDelete,
872	}: {
873		provider: KeatingCustomProvider;
874		isAutoDiscovery: boolean;
875		onEdit: () => void;
876		onDelete: () => void;
877	}) {
878		return (
879			<div className="rounded-lg border border-border p-4">
880				<div className="flex items-start justify-between gap-3">
881					<div className="min-w-0">
882						<div className="text-sm font-medium text-foreground">{provider.name}</div>
883						<div className="text-xs text-muted-foreground mt-0.5">
884							{provider.type === "gateway" ? `${provider.gatewayKind ?? "generic"} gateway` : provider.type} · {provider.baseUrl}
885						</div>
886						<div className="flex gap-2 mt-1">
887							<span className="inline-flex items-center rounded-full bg-muted px-2 py-0.5 text-[10px] font-medium text-muted-foreground">
888								{isAutoDiscovery ? "Auto-discovery" : "Manual"}
889							</span>
890							<span className="inline-flex items-center rounded-full bg-muted px-2 py-0.5 text-[10px] font-medium text-muted-foreground">
891								{isAutoDiscovery
892									? `${provider.models?.length ?? 0} discovered models`
893									: `${provider.models?.length ?? 0} configured models`}
894							</span>
895						</div>
896					</div>
897					<div className="flex items-center gap-1 shrink-0">
898						<button
899							className="inline-flex h-7 w-7 items-center justify-center rounded-md text-muted-foreground hover:bg-accent hover:text-accent-foreground"
900							onClick={onEdit}
901							aria-label="Edit provider"
902						>
903							<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M17 3a2.85 2.83 0 1 1 4 4L7.5 20.5 2 22l1.5-5.5Z"/><path d="m15 5 4 4"/></svg>
904						</button>
905						<button
906							className="inline-flex h-7 w-7 items-center justify-center rounded-md text-destructive hover:bg-destructive/10"
907							onClick={onDelete}
908							aria-label="Delete provider"
909						>
910							<Trash2 size={14} />
911						</button>
912					</div>
913				</div>
914			</div>
915		);
916	}
