38	function modelCost() {
39		return {
40			input: 0,
41			output: 0,
42			cacheRead: 0,
43			cacheWrite: 0,
44		};
45	}
46	
47	function toContextWindow(value: unknown, fallback = 0): number {
48		if (typeof value === "number" && Number.isFinite(value)) return value;
49		if (typeof value === "string") {
50			const parsed = Number.parseInt(value, 10);
51			if (Number.isFinite(parsed)) return parsed;
52		}
53		return fallback;
54	}
55	
56	function inferInputModes(model: any): Array<"text" | "image"> {
57		const supported = new Set<string>();
58	
59		if (Array.isArray(model?.input)) {
60			for (const entry of model.input) {
61				if (entry === "image" || entry === "text") supported.add(entry);
62			}
63		}
64	
65		if (Array.isArray(model?.input_modalities)) {
66			for (const entry of model.input_modalities) {
67				if (entry === "image" || entry === "text") supported.add(entry);
68			}
69		}
70	
71		if (Array.isArray(model?.modalities)) {
72			for (const entry of model.modalities) {
73				if (entry === "image" || entry === "text") supported.add(entry);
74			}
75		}
76	
77		if (model?.vision === true) supported.add("image");
78		if (supported.size === 0) supported.add("text");
79	
80		return Array.from(supported) as Array<"text" | "image">;
81	}
82	
83	function inferReasoning(model: any): boolean {
84		if (typeof model?.reasoning === "boolean") return model.reasoning;
85		if (typeof model?.supports_reasoning === "boolean") return model.supports_reasoning;
86		if (Array.isArray(model?.capabilities)) return model.capabilities.includes("thinking");
87		const name = String(model?.id ?? model?.name ?? "").toLowerCase();
88		return name.includes("thinking") || name.includes("reasoning");
89	}
