91	function manualProviderApi(type: KeatingCustomProviderType): Api {
92		switch (type) {
93			case "openai-responses":
94				return "openai-responses" as Api;
95			case "anthropic-messages":
96				return "anthropic-messages" as Api;
97			case "synthetic":
98			case "openai-completions":
99			default:
100				return "openai-completions" as Api;
101		}
102	}
103	
104	function openAiCompatibleBaseUrls(provider: KeatingCustomProvider): string[] {
105		const baseUrl = trimTrailingSlash(provider.baseUrl);
106		if (baseUrl.endsWith("/v1")) return [baseUrl];
107	
108		if (provider.type === "gateway" && provider.gatewayKind === "bifrost") {
109			return [`${baseUrl}/v1`, `${baseUrl}/openai/v1`, baseUrl];
110		}
111	
112		if (provider.type === "gateway") {
113			return [`${baseUrl}/v1`, baseUrl];
114		}
115	
116		return [baseUrl, `${baseUrl}/v1`];
117	}
