119	async function fetchJson(url: string, apiKey?: string, options: { method?: "GET" | "POST"; body?: unknown } = {}): Promise<any> {
120		const proxied = proxiedProviderRequestUrl(url);
121		const headers: Record<string, string> = {
122			"x-target-url": proxied.targetBaseUrl,
123		};
124	
125		if (options.body !== undefined) headers["Content-Type"] = "application/json";
126		if (apiKey) {
127			headers.Authorization = `Bearer ${apiKey}`;
128		}
129	
130		const response = await withApiRetry(async () => {
131			const result = await fetch(proxied.url, {
132				method: options.method ?? "GET",
133				headers,
134				body: options.body === undefined ? undefined : JSON.stringify(options.body),
135			});
136			if (!result.ok) {
137				const retryAfter = result.headers.get("retry-after");
138				throw new Error(`HTTP ${result.status}: ${result.statusText}${retryAfter ? ` retry-after: ${retryAfter}` : ""}`);
139			}
140			return result;
141		});
142	
143		return await response.json();
144	}
145	
146	async function discoverOpenAiCompatibleModels(
147		provider: KeatingCustomProvider,
148	): Promise<{ apiBaseUrl: string; models: Model<Api>[] }> {
149		const candidateBaseUrls = openAiCompatibleBaseUrls(provider);
150	
151		let lastError: unknown;
