import { spawn } from "node:child_process";
import WebSocket from "ws";

const PORT = 9777;
const chrome = spawn("google-chrome", [
  "--headless=new", `--remote-debugging-port=${PORT}`,
  "--no-sandbox", "--disable-gpu", "--hide-scrollbars",
  "--window-size=1200,900", "about:blank",
], { stdio: "ignore" });

const sleep = (ms) => new Promise((r) => setTimeout(r, ms));

async function getWsUrl() {
  for (let i = 0; i < 50; i++) {
    try {
      const r = await fetch(`http://localhost:${PORT}/json/version`);
      const j = await r.json();
      if (j.webSocketDebuggerUrl) return j.webSocketDebuggerUrl;
    } catch {}
    await sleep(200);
  }
  throw new Error("no chrome");
}

const wsUrl = await getWsUrl();
const ws = new WebSocket(wsUrl, { perMessageDeflate: false, maxPayload: 256 * 1024 * 1024 });
let id = 0;
const pending = new Map();
const sessions = {};
ws.on("message", (d) => {
  const m = JSON.parse(d.toString());
  if (m.id && pending.has(m.id)) { pending.get(m.id)(m); pending.delete(m.id); }
});
await new Promise((r) => ws.on("open", r));
function send(method, params = {}, sessionId) {
  return new Promise((resolve) => {
    const mid = ++id;
    pending.set(mid, resolve);
    ws.send(JSON.stringify({ id: mid, method, params, sessionId }));
  });
}

// attach to a page target
const { result: targets } = await send("Target.getTargets");
let pageTarget = targets.targetInfos.find((t) => t.type === "page");
const { result: att } = await send("Target.attachToTarget", { targetId: pageTarget.targetId, flatten: true });
const sessionId = att.sessionId;

async function evalJs(expr, sessionId) {
  const r = await send("Runtime.evaluate", { expression: expr, returnByValue: true, awaitPromise: true }, sessionId);
  if (r.result?.exceptionDetails) throw new Error(JSON.stringify(r.result.exceptionDetails));
  return r.result?.result?.value;
}

await send("Page.enable", {}, sessionId);
await send("Runtime.enable", {}, sessionId);
await send("Page.navigate", { url: "http://localhost:3000/" }, sessionId);
await sleep(3500);

const DOM = `<div id="settings-section-custom-providers" class="flex flex-col gap-4 scroll-mt-20"><div class="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between sm:gap-4"><div class="min-w-0"><h3 class="text-sm font-semibold text-foreground mb-2">Custom Providers</h3><p class="text-sm text-muted-foreground">User-configured servers with auto-discovered or manually defined models.</p></div><div class="relative w-full sm:w-auto shrink-0"><button type="button" class="dialog-compact-button inline-flex w-full sm:w-auto items-center justify-between gap-2 rounded-md border border-border bg-background px-3 py-1.5 text-xs font-medium"><span>Add Provider</span></button></div></div></div>`;

for (const vw of [760, 900, 1100]) {
  await send("Emulation.setDeviceMetricsOverride", { width: vw, height: 900, deviceScaleFactor: 1, mobile: false }, sessionId);
  await sleep(150);
  const out = await evalJs(`(() => {
    document.querySelectorAll('#__probe').forEach(n=>n.remove());
    const host = document.createElement('div');
    host.id='__probe';
    host.setAttribute('role','dialog');
    // emulate the dialog content column width: viewport - sidebar(~216) - padding(~40)
    host.style.cssText = 'position:fixed;top:0;left:0;z-index:99999;background:#fff;width:'+(${vw}-216-40)+'px;padding:16px;border:2px solid red;';
    host.innerHTML = ${JSON.stringify(DOM)};
    document.body.appendChild(host);
    const row = host.querySelector('.flex.flex-col.gap-3');
    const textCol = host.querySelector('.min-w-0');
    const btnWrap = host.querySelector('.relative');
    const btn = host.querySelector('button');
    const cs = (el)=>getComputedStyle(el);
    const rect = (el)=>{const r=el.getBoundingClientRect();return {w:Math.round(r.width),h:Math.round(r.height)};};
    return JSON.stringify({
      vw: ${vw},
      hostW: host.clientWidth,
      rowDisplay: cs(row).display, rowFlexDir: cs(row).flexDirection,
      textCol: rect(textCol), textColCss: cs(textCol).width,
      btnWrap: rect(btnWrap), btnWrapCss: cs(btnWrap).width,
      btn: rect(btn), btnCssWidth: cs(btn).width,
      pLines: host.querySelector('p').getBoundingClientRect().height,
    }, null, 0);
  })()`, sessionId);
  console.log(out);
}

chrome.kill();
ws.close();
process.exit(0);

